// 1. Текущий элемент после ноды "Подготовка AI-ответа"
const current = $input.item.json;

// 2. Базовые данные заявки до AI — берём из ноды
const base = $items("2 Update Request Employee Feedback.1", 0, 0).json;

try {
  const raw = current.ai_raw_output;

  if (typeof raw !== 'string') {
    throw new Error('ai_raw_output is not a string');
  }

  const parsed = JSON.parse(raw);

  // Минимальная валидация
  if (typeof parsed.ai_performance_score !== 'number') {
    throw new Error('ai_performance_score must be a number');
  }
  if (!['high', 'medium', 'low'].includes(parsed.ai_alignment)) {
    throw new Error('ai_alignment must be high|medium|low');
  }
  if (!['approve_raise', 'keep_salary', 'reject_request', 'need_more_info'].includes(parsed.ai_recommendation)) {
    throw new Error('invalid ai_recommendation');
  }

  // Склеиваем: база заявки + результат AI
  return {
    json: {
      ...base,
      ai_performance_score: parsed.ai_performance_score,
      ai_alignment: parsed.ai_alignment,
      ai_recommendation: parsed.ai_recommendation,
      ai_comment: parsed.ai_comment ?? '',
    },
  };

} catch (error) {
  throw new Error('AI_JSON_PARSE_ERROR: ' + (error.message || 'unknown error'));
}

