// employees приходят с входа 0 (Google Sheets Employees_DEV)
const employees = $items(0);

// заявка + AI приходят с входа 1 (Обновить заявку результатом ИИ)
const reqItem = $items(1, 0);

if (!reqItem || !reqItem.json) {
  throw new Error("REQUEST_INPUT_NOT_FOUND");
}

const req = reqItem.json;
const targetId = req.employee_matrix_user_id;

if (!targetId) {
  throw new Error("EMPLOYEE_MATRIX_USER_ID_EMPTY");
}

// Фильтруем сотрудников по matrix_user_id
const matched = employees.filter(e => e.json.matrix_user_id === targetId);

if (matched.length === 0) {
  throw new Error("EMPLOYEE_NOT_FOUND_IN_EMPLOYEES_DEV: " + targetId);
}

const emp = matched[0].json;

// Склеиваем заявку + AI + HR-данные сотрудника в один объект
return [
  {
    json: {
      ...req,
      full_name: emp.full_name,
      department: emp.department,
      grade: emp.grade,
    },
  },
];

